   1→//! GitHub Copilot provider.
   2→//!
   3→//! Authentication uses the GitHub device-flow OAuth to obtain a GitHub token,
   4→//! then exchanges it for a short-lived Copilot API token via
   5→//! `https://api.github.com/copilot_internal/v2/token`.
   6→//!
   7→//! The Copilot API itself is OpenAI-compatible (`/chat/completions`).
   8→
   9→use std::{collections::HashSet, pin::Pin, sync::mpsc, time::Duration};
  10→
  11→use {
  12→    async_trait::async_trait,
  13→    futures::StreamExt,
  14→    moltis_oauth::{OAuthTokens, TokenStore},
  15→    secrecy::{ExposeSecret, Secret},
  16→    tokio_stream::Stream,
  17→    tracing::{debug, trace, warn},
  18→};
  19→
  20→use {
  21→    super::openai_compat::{
  22→        SseLineResult, StreamingToolState, finalize_stream, parse_openai_compat_usage_from_payload,
  23→        parse_tool_calls, process_openai_sse_line, to_openai_tools,
  24→    },
  25→    moltis_agents::model::{ChatMessage, CompletionResponse, LlmProvider, StreamEvent},
  26→};
  27→
  28→// ── Constants ────────────────────────────────────────────────────────────────
  29→
  30→/// GitHub OAuth app client ID for Copilot (VS Code's public client ID).
  31→const GITHUB_CLIENT_ID: &str = "Iv1.b507a08c87ecfe98";
  32→
  33→const GITHUB_DEVICE_CODE_URL: &str = "https://github.com/login/device/code";
  34→const GITHUB_TOKEN_URL: &str = "https://github.com/login/oauth/access_token";
  35→const COPILOT_TOKEN_URL: &str = "https://api.github.com/copilot_internal/v2/token";
  36→const COPILOT_API_BASE: &str = "https://api.individual.githubcopilot.com";
  37→const COPILOT_MODELS_ENDPOINT: &str = "https://api.individual.githubcopilot.com/models";
  38→
  39→const PROVIDER_NAME: &str = "github-copilot";
  40→
  41→/// Required headers for the Copilot chat completions API.
  42→/// The API rejects requests without `Editor-Version`.
  43→const EDITOR_VERSION: &str = "vscode/1.96.2";
  44→const COPILOT_USER_AGENT: &str = "GitHubCopilotChat/0.26.7";
  45→
  46→// ── Device flow types ────────────────────────────────────────────────────────
  47→
  48→#[derive(Debug, serde::Deserialize)]
  49→pub struct DeviceCodeResponse {
  50→    pub device_code: String,
  51→    pub user_code: String,
  52→    pub verification_uri: String,
  53→    pub interval: u64,
  54→}
  55→
  56→#[derive(Debug, serde::Deserialize)]
  57→struct GithubTokenResponse {
  58→    access_token: Option<String>,
  59→    error: Option<String>,
  60→}
  61→
  62→#[derive(Debug, serde::Deserialize)]
  63→struct CopilotTokenResponse {
  64→    token: String,
  65→    expires_at: u64,
  66→}
  67→
  68→// ── Provider ─────────────────────────────────────────────────────────────────
  69→
  70→pub struct GitHubCopilotProvider {
  71→    model: String,
  72→    client: &'static reqwest::Client,
  73→    token_store: TokenStore,
  74→}
  75→
  76→impl GitHubCopilotProvider {
  77→    pub fn new(model: String) -> Self {
  78→        Self {
  79→            model,
  80→            client: crate::shared_http_client(),
  81→            token_store: TokenStore::new(),
  82→        }
  83→    }
  84→
  85→    /// Start the GitHub device-flow: request a device code from GitHub.
  86→    pub async fn request_device_code(
  87→        client: &reqwest::Client,
  88→    ) -> anyhow::Result<DeviceCodeResponse> {
  89→        let resp = client
  90→            .post(GITHUB_DEVICE_CODE_URL)
  91→            .header("Accept", "application/json")
  92→            .form(&[("client_id", GITHUB_CLIENT_ID), ("scope", "")])
  93→            .send()
  94→            .await?;
  95→
  96→        if !resp.status().is_success() {
  97→            let body = resp.text().await.unwrap_or_default();
  98→            anyhow::bail!("GitHub device code request failed: {body}");
  99→        }
 100→
 101→        Ok(resp.json().await?)
 102→    }
 103→
 104→    /// Poll GitHub for the access token after the user has entered the code.
 105→    pub async fn poll_for_token(
 106→        client: &reqwest::Client,
 107→        device_code: &str,
 108→        interval: u64,
 109→    ) -> anyhow::Result<String> {
 110→        loop {
 111→            tokio::time::sleep(Duration::from_secs(interval)).await;
 112→
 113→            let resp = client
 114→                .post(GITHUB_TOKEN_URL)
 115→                .header("Accept", "application/json")
 116→                .form(&[
 117→                    ("client_id", GITHUB_CLIENT_ID),
 118→                    ("device_code", device_code),
 119→                    ("grant_type", "urn:ietf:params:oauth:grant-type:device_code"),
 120→                ])
 121→                .send()
 122→                .await?;
 123→
 124→            let body: GithubTokenResponse = resp.json().await?;
 125→
 126→            if let Some(token) = body.access_token {
 127→                return Ok(token);
 128→            }
 129→
 130→            match body.error.as_deref() {
 131→                Some("authorization_pending") => continue,
 132→                Some("slow_down") => {
 133→                    tokio::time::sleep(Duration::from_secs(5)).await;
 134→                    continue;
 135→                },
 136→                Some(err) => anyhow::bail!("GitHub device flow error: {err}"),
 137→                None => anyhow::bail!("unexpected response from GitHub token endpoint"),
 138→            }
 139→        }
 140→    }
 141→
 142→    /// Get a valid Copilot API token, exchanging the GitHub token if needed.
 143→    async fn get_valid_copilot_token(&self) -> anyhow::Result<String> {
 144→        fetch_valid_copilot_token_with_fallback(self.client, &self.token_store).await
 145→    }
 146→}
