 153→fn token_store_with_provider_tokens(primary: &TokenStore) -> Option<TokenStore> {
 154→    debug!("checking primary token store for {PROVIDER_NAME}");
 155→    if primary.load(PROVIDER_NAME).is_some() {
 156→        debug!("found {PROVIDER_NAME} tokens in primary store");
 157→        return Some(primary.clone());
 158→    }
 159→    if let Some(home_store) = home_token_store_if_different() {
 160→        debug!("checking home token store for {PROVIDER_NAME}");
 161→        if home_store.load(PROVIDER_NAME).is_some() {
 162→            debug!("found {PROVIDER_NAME} tokens in home store");
 163→            return Some(home_store);
 164→        }
 165→    }
 166→    debug!("{PROVIDER_NAME} tokens not found in any store");
 167→    None
