 186→    ("gpt-4.1", "GPT-4.1 (Copilot)"),
 187→    ("gpt-4.1-mini", "GPT-4.1 Mini (Copilot)"),
 188→    ("gpt-4.1-nano", "GPT-4.1 Nano (Copilot)"),
 189→    ("o1", "o1 (Copilot)"),
