 195→
 196→async fn fetch_valid_copilot_token(
 197→    client: &reqwest::Client,
 198→    token_store: &TokenStore,
 199→) -> anyhow::Result<String> {
 200→    let tokens = token_store.load(PROVIDER_NAME).ok_or_else(|| {
 201→        anyhow::anyhow!("not logged in to github-copilot — run OAuth device flow first")
 202→    })?;
 203→
 204→    // The `access_token` stored is the GitHub user token.
 205→    // We exchange it for a short-lived Copilot API token and cache it.
 206→    if let Some(copilot_tokens) = token_store.load("github-copilot-api")
 207→        && let Some(expires_at) = copilot_tokens.expires_at
 208→    {
 209→        let now = std::time::SystemTime::now()
 210→            .duration_since(std::time::UNIX_EPOCH)
 211→            .unwrap_or_default()
 212→            .as_secs();
 213→        if now + 60 < expires_at {
 214→            return Ok(copilot_tokens.access_token.expose_secret().clone());
 215→        }
 216→    }
 217→
 218→    let resp = client
 219→        .get(COPILOT_TOKEN_URL)
 220→        .header(
 221→            "Authorization",
 222→            format!("token {}", tokens.access_token.expose_secret()),
 223→        )
 224→        .header("Accept", "application/json")
 225→        .header(
 226→            "User-Agent",
 227→            "moltis/0.1.0 (GitHub Copilot compatible client)",
 228→        )
 229→        .send()
 230→        .await?;
 231→
 232→    if !resp.status().is_success() {
 233→        let body = resp.text().await.unwrap_or_default();
 234→        anyhow::bail!("Copilot token exchange failed: {body}");
 235→    }
 236→
 237→    let copilot_resp: CopilotTokenResponse = resp.json().await?;
 238→    let _ = token_store.save("github-copilot-api", &OAuthTokens {
 239→        access_token: Secret::new(copilot_resp.token.clone()),
 240→        refresh_token: None,
 241→        id_token: None,
 242→        account_id: None,
 243→        expires_at: Some(copilot_resp.expires_at),
 244→    });
 245→
 246→    Ok(copilot_resp.token)
 247→}
 248→
 249→async fn fetch_valid_copilot_token_with_fallback(
 250→    client: &reqwest::Client,
 251→    primary_store: &TokenStore,
 252→) -> anyhow::Result<String> {
 253→    let Some(token_store) = token_store_with_provider_tokens(primary_store) else {
 254→        anyhow::bail!("not logged in to github-copilot — run OAuth device flow first");
 255→    };
 256→    fetch_valid_copilot_token(client, &token_store).await
 257→}
