 265→
 266→fn normalize_display_name(model_id: &str, display_name: Option<&str>) -> String {
 267→    let normalized = display_name
 268→        .map(str::trim)
 269→        .filter(|s| !s.is_empty())
 270→        .unwrap_or(model_id);
 271→    if normalized == model_id {
 272→        model_id.to_string()
 273→    } else {
 274→        normalized.to_string()
 275→    }
 276→}
 277→
 278→fn is_likely_model_id(model_id: &str) -> bool {
 279→    if model_id.is_empty() || model_id.len() > 120 {
 280→        return false;
 281→    }
 282→    if model_id.chars().any(char::is_whitespace) {
 283→        return false;
 284→    }
 285→    model_id
 286→        .chars()
 287→        .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.' | ':'))
 288→}
 289→
 290→fn parse_model_entry(entry: &serde_json::Value) -> Option<super::DiscoveredModel> {
 291→    let obj = entry.as_object()?;
 292→    let model_id = obj
 293→        .get("id")
 294→        .or_else(|| obj.get("slug"))
 295→        .or_else(|| obj.get("model"))
 296→        .and_then(serde_json::Value::as_str)?;
 297→
 298→    if !is_likely_model_id(model_id) {
 299→        return None;
 300→    }
 301→
 302→    let display_name = obj
 303→        .get("display_name")
 304→        .or_else(|| obj.get("displayName"))
 305→        .or_else(|| obj.get("name"))
 306→        .or_else(|| obj.get("title"))
 307→        .and_then(serde_json::Value::as_str);
 308→
 309→    let created_at = obj.get("created").and_then(serde_json::Value::as_i64);
 310→
 311→    Some(
 312→        super::DiscoveredModel::new(model_id, normalize_display_name(model_id, display_name))
 313→            .with_created_at(created_at),
 314→    )
 315→}
 316→
 317→fn collect_candidate_arrays<'a>(
 318→    value: &'a serde_json::Value,
 319→    out: &mut Vec<&'a serde_json::Value>,
 320→) {
 321→    match value {
 322→        serde_json::Value::Array(items) => out.extend(items),
 323→        serde_json::Value::Object(map) => {
 324→            for key in ["models", "data", "items", "results", "available"] {
 325→                if let Some(nested) = map.get(key) {
 326→                    collect_candidate_arrays(nested, out);
 327→                }
 328→            }
 329→        },
 330→        _ => {},
 331→    }
 332→}
 333→
 334→fn parse_models_payload(value: &serde_json::Value) -> Vec<super::DiscoveredModel> {
 335→    let mut candidates = Vec::new();
 336→    collect_candidate_arrays(value, &mut candidates);
 337→
 338→    let mut models = Vec::new();
 339→    let mut seen = HashSet::new();
 340→    for entry in candidates {
 341→        if let Some(model) = parse_model_entry(entry)
 342→            && seen.insert(model.id.clone())
 343→        {
 344→            models.push(model);
 345→        }
 346→    }
 347→
 348→    // Sort by created_at descending (newest first). Models without a
 349→    // timestamp are placed after those with one, preserving relative order.
 350→    models.sort_by(|a, b| match (a.created_at, b.created_at) {
 351→        (Some(a_ts), Some(b_ts)) => b_ts.cmp(&a_ts), // newest first
 352→        (Some(_), None) => std::cmp::Ordering::Less, // timestamp before no-timestamp
 353→        (None, Some(_)) => std::cmp::Ordering::Greater,
 354→        (None, None) => std::cmp::Ordering::Equal,
 355→    });
 356→
 357→    models
 358→}
 359→
 360→async fn fetch_models_from_api(
 361→    client: &reqwest::Client,
 362→    access_token: String,
 363→) -> anyhow::Result<Vec<super::DiscoveredModel>> {
 364→    let response = client
 365→        .get(COPILOT_MODELS_ENDPOINT)
 366→        .header("Authorization", format!("Bearer {access_token}"))
 367→        .header("Accept", "application/json")
 368→        .header("Editor-Version", EDITOR_VERSION)
 369→        .header("User-Agent", COPILOT_USER_AGENT)
 370→        .send()
 371→        .await?;
 372→    let status = response.status();
 373→    let body = response.text().await?;
 374→    if !status.is_success() {
 375→        anyhow::bail!("copilot models API error HTTP {status}");
 376→    }
 377→    let payload: serde_json::Value = serde_json::from_str(&body)?;
 378→    let models = parse_models_payload(&payload);
 379→    if models.is_empty() {
 380→        anyhow::bail!("copilot models API returned no models");
 381→    }
 382→    Ok(models)
 383→}
 384→
 385→/// Spawn model discovery in a background thread and return the receiver
 386→/// immediately, without blocking.
 387→pub fn start_model_discovery() -> mpsc::Receiver<anyhow::Result<Vec<super::DiscoveredModel>>> {
 388→    let (tx, rx) = mpsc::sync_channel(1);
 389→    std::thread::spawn(move || {
 390→        let result = tokio::runtime::Builder::new_current_thread()
 391→            .enable_all()
 392→            .build()
 393→            .map_err(anyhow::Error::from)
 394→            .and_then(|rt| {
 395→                rt.block_on(async {
 396→                    let client = reqwest::Client::builder()
 397→                        .timeout(Duration::from_secs(8))
 398→                        .build()?;
 399→                    let token_store = TokenStore::new();
 400→                    let access_token =
 401→                        fetch_valid_copilot_token_with_fallback(&client, &token_store).await?;
 402→                    fetch_models_from_api(&client, access_token).await
 403→                })
 404→            });
 405→        let _ = tx.send(result);
 406→    });
 407→    rx
 408→}
 409→
 410→fn fetch_models_blocking() -> anyhow::Result<Vec<super::DiscoveredModel>> {
 411→    start_model_discovery()
 412→        .recv()
 413→        .map_err(|err| anyhow::anyhow!("copilot model discovery worker failed: {err}"))?
 414→}
 415→
 416→pub fn live_models() -> anyhow::Result<Vec<super::DiscoveredModel>> {
 417→    let models = fetch_models_blocking()?;
 418→    debug!(
 419→        model_count = models.len(),
 420→        "loaded github-copilot live models"
 421→    );
 422→    Ok(models)
 423→}
 424→
 425→pub fn available_models() -> Vec<super::DiscoveredModel> {
 426→    let fallback = default_model_catalog();
 427→    let discovered = match live_models() {
 428→        Ok(models) => models,
 429→        Err(err) => {
 430→            let msg = err.to_string();
 431→            if msg.contains("not logged in") || msg.contains("tokens not found") {
 432→                debug!(error = %err, "github-copilot not configured, using fallback catalog");
 433→            } else {
 434→                warn!(error = %err, "failed to fetch github-copilot models, using fallback catalog");
 435→            }
 436→            return fallback;
 437→        },
 438→    };
 439→
 440→    super::merge_discovered_with_fallback_catalog(discovered, fallback)
 441→}
