 459→    async fn complete(
 460→        &self,
 461→        messages: &[ChatMessage],
 462→        tools: &[serde_json::Value],
 463→    ) -> anyhow::Result<CompletionResponse> {
 464→        let token = self.get_valid_copilot_token().await?;
 465→
 466→        let openai_messages: Vec<serde_json::Value> =
 467→            messages.iter().map(ChatMessage::to_openai_value).collect();
 468→        let mut body = serde_json::json!({
 469→            "model": self.model,
 470→            "messages": openai_messages,
 471→        });
 472→
 473→        if !tools.is_empty() {
 474→            body["tools"] = serde_json::Value::Array(to_openai_tools(tools));
 475→        }
 476→
 477→        debug!(
 478→            model = %self.model,
 479→            messages_count = messages.len(),
 480→            tools_count = tools.len(),
 481→            "github-copilot complete request"
 482→        );
 483→        trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "github-copilot request body");
 484→
 485→        let http_resp = self
 486→            .client
 487→            .post(format!("{COPILOT_API_BASE}/chat/completions"))
 488→            .header("Authorization", format!("Bearer {token}"))
 489→            .header("content-type", "application/json")
 490→            .header("Editor-Version", EDITOR_VERSION)
 491→            .header("User-Agent", COPILOT_USER_AGENT)
 492→            .json(&body)
 493→            .send()
 494→            .await?;
 495→
 496→        let status = http_resp.status();
 497→        if !status.is_success() {
 498→            let retry_after_ms = super::retry_after_ms_from_headers(http_resp.headers());
 499→            let body_text = http_resp.text().await.unwrap_or_default();
 500→            warn!(status = %status, body = %body_text, "github-copilot API error");
 501→            anyhow::bail!(
 502→                "{}",
 503→                super::with_retry_after_marker(
 504→                    format!("GitHub Copilot API error HTTP {status}: {body_text}"),
 505→                    retry_after_ms,
 506→                )
 507→            );
 508→        }
 509→
 510→        let resp = http_resp.json::<serde_json::Value>().await?;
 511→        trace!(response = %resp, "github-copilot raw response");
 512→
 513→        let message = &resp["choices"][0]["message"];
 514→
 515→        let text = message["content"].as_str().map(|s| s.to_string());
 516→        let tool_calls = parse_tool_calls(message);
 517→
 518→        let usage = parse_openai_compat_usage_from_payload(&resp).unwrap_or_default();
 519→
 520→        Ok(CompletionResponse {
 521→            text,
 522→            tool_calls,
 523→            usage,
 524→        })
 525→    }
 526→
 527→    #[allow(clippy::collapsible_if)]
 528→    fn stream(
 529→        &self,
 530→        messages: Vec<ChatMessage>,
 531→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
 532→        self.stream_with_tools(messages, vec![])
 533→    }
 534→
 535→    #[allow(clippy::collapsible_if)]
 536→    fn stream_with_tools(
 537→        &self,
 538→        messages: Vec<ChatMessage>,
 539→        tools: Vec<serde_json::Value>,
 540→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
 541→        Box::pin(async_stream::stream! {
 542→            let token = match self.get_valid_copilot_token().await {
 543→                Ok(t) => t,
 544→                Err(e) => {
 545→                    yield StreamEvent::Error(e.to_string());
 546→                    return;
 547→                }
 548→            };
 549→
 550→            let openai_messages: Vec<serde_json::Value> =
 551→                messages.iter().map(ChatMessage::to_openai_value).collect();
 552→            let mut body = serde_json::json!({
 553→                "model": self.model,
 554→                "messages": openai_messages,
 555→                "stream": true,
 556→                "stream_options": { "include_usage": true },
 557→            });
 558→
 559→            if !tools.is_empty() {
 560→                body["tools"] = serde_json::Value::Array(to_openai_tools(&tools));
 561→            }
 562→
 563→            debug!(
 564→                model = %self.model,
 565→                messages_count = openai_messages.len(),
 566→                tools_count = tools.len(),
 567→                "github-copilot stream_with_tools request"
 568→            );
 569→            trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "github-copilot stream request body");
 570→
 571→            let resp = match self
 572→                .client
 573→                .post(format!("{COPILOT_API_BASE}/chat/completions"))
 574→                .header("Authorization", format!("Bearer {token}"))
 575→                .header("content-type", "application/json")
 576→                .header("Editor-Version", EDITOR_VERSION)
 577→                .header("User-Agent", COPILOT_USER_AGENT)
 578→                .json(&body)
 579→                .send()
 580→                .await
 581→            {
 582→                Ok(r) => {
 583→                    if let Err(e) = r.error_for_status_ref() {
 584→                        let status = e.status().map(|s| s.as_u16()).unwrap_or(0);
 585→                        let retry_after_ms = super::retry_after_ms_from_headers(r.headers());
 586→                        let body_text = r.text().await.unwrap_or_default();
 587→                        yield StreamEvent::Error(super::with_retry_after_marker(
 588→                            format!("HTTP {status}: {body_text}"),
 589→                            retry_after_ms,
 590→                        ));
 591→                        return;
 592→                    }
 593→                    r
 594→                }
 595→                Err(e) => {
 596→                    yield StreamEvent::Error(e.to_string());
 597→                    return;
 598→                }
 599→            };
 600→
 601→            let mut byte_stream = resp.bytes_stream();
 602→            let mut buf = String::new();
 603→            let mut state = StreamingToolState::default();
 604→
 605→            while let Some(chunk) = byte_stream.next().await {
 606→                let chunk = match chunk {
 607→                    Ok(c) => c,
 608→                    Err(e) => {
 609→                        yield StreamEvent::Error(e.to_string());
 610→                        return;
 611→                    }
 612→                };
 613→                buf.push_str(&String::from_utf8_lossy(&chunk));
 614→
 615→                while let Some(pos) = buf.find('\n') {
 616→                    let line = buf[..pos].trim().to_string();
 617→                    buf = buf[pos + 1..].to_string();
 618→
 619→                    if line.is_empty() {
 620→                        continue;
 621→                    }
 622→
 623→                    let Some(data) = line
 624→                        .strip_prefix("data: ")
 625→                        .or_else(|| line.strip_prefix("data:"))
 626→                    else {
 627→                        continue;
 628→                    };
 629→
 630→                    match process_openai_sse_line(data, &mut state) {
 631→                        SseLineResult::Done => {
 632→                            for event in finalize_stream(&mut state) {
 633→                                yield event;
 634→                            }
 635→                            return;
 636→                        }
 637→                        SseLineResult::Events(events) => {
 638→                            for event in events {
 639→                                yield event;
 640→                            }
 641→                        }
 642→                        SseLineResult::Skip => {}
 643→                    }
 644→                }
 645→            }
 646→
 647→            let line = buf.trim().to_string();
 648→            if !line.is_empty()
 649→                && let Some(data) = line
 650→                    .strip_prefix("data: ")
 651→                    .or_else(|| line.strip_prefix("data:"))
 652→            {
 653→                match process_openai_sse_line(data, &mut state) {
 654→                    SseLineResult::Done => {
 655→                        for event in finalize_stream(&mut state) {
 656→                            yield event;
 657→                        }
 658→                        return;
 659→                    }
 660→                    SseLineResult::Events(events) => {
 661→                        for event in events {
 662→                            yield event;
 663→                        }
 664→                    }
 665→                    SseLineResult::Skip => {}
 666→                }
 667→            }
 668→
 669→            for event in finalize_stream(&mut state) {
 670→                yield event;
 671→            }
 672→        })
 673→    }
 674→}
