  1→//! Shared helpers for OpenAI-compatible streaming with tools.
  2→//!
  3→//! This module provides reusable functions for parsing OpenAI-style SSE streams
  4→//! that include tool calls. Used by openai.rs, github_copilot.rs, and kimi_code.rs.
  5→
  6→use std::collections::HashMap;
  7→
  8→use {serde::Serialize, tracing::trace};
  9→
 10→use moltis_agents::model::{ChatMessage, StreamEvent, ToolCall, Usage, UserContent};
 11→
 12→// ============================================================================
 13→// OpenAI Tool Schema Types
 14→// ============================================================================
 15→// These types enforce the correct structure for OpenAI-compatible APIs.
 16→// Using typed structs instead of manual JSON prevents missing fields at compile time.
 17→//
 18→// References:
 19→// - Chat Completions: https://platform.openai.com/docs/guides/function-calling
 20→// - Responses API: https://learn.microsoft.com/en-us/azure/ai-foundry/openai/how-to/responses
 21→// ============================================================================
 22→
 23→/// Chat Completions API tool format (nested under "function").
 24→///
 25→/// ```json
 26→/// { "type": "function", "function": { "name": "...", ... } }
 27→/// ```
 28→#[derive(Debug, Serialize)]
 29→pub struct ChatCompletionsTool {
 30→    #[serde(rename = "type")]
 31→    pub tool_type: &'static str,
 32→    pub function: ChatCompletionsFunction,
 33→}
 34→
 35→/// The function definition nested inside ChatCompletionsTool.
 36→#[derive(Debug, Serialize)]
 37→pub struct ChatCompletionsFunction {
 38→    pub name: String,
 39→    pub description: String,
 40→    pub parameters: serde_json::Value,
 41→    pub strict: bool,
 42→}
 43→
 44→/// Responses API tool format (flat, name at top level).
 45→///
 46→/// ```json
 47→/// { "type": "function", "name": "...", "parameters": {...}, "strict": true }
 48→/// ```
 49→#[derive(Debug, Serialize)]
 50→pub struct ResponsesApiTool {
 51→    #[serde(rename = "type")]
 52→    pub tool_type: &'static str,
 53→    pub name: String,
 54→    pub description: String,
 55→    pub parameters: serde_json::Value,
 56→    pub strict: bool,
 57→}
