 59→/// Make a JSON Schema node nullable by adding `"null"` to its type.
 60→///
 61→/// For schemas using `"type": "string"` (or any single type), this converts to
 62→/// `"type": ["string", "null"]`.  For schemas using `anyOf`/`oneOf`, it appends
 63→/// a `{"type": "null"}` variant.  Already-nullable schemas are left unchanged.
 64→fn make_nullable(schema: &mut serde_json::Value) {
 65→    let Some(obj) = schema.as_object_mut() else {
 66→        return;
 67→    };
 68→
 69→    // If it already has a "null" type, nothing to do.
 70→    if let Some(ty) = obj.get("type") {
 71→        if ty.as_str() == Some("null") {
 72→            return;
 73→        }
 74→        if let Some(arr) = ty.as_array()
 75→            && arr.iter().any(|v| v.as_str() == Some("null"))
 76→        {
 77→            return;
 78→        }
 79→    }
 80→
 81→    // Case 1: has a `type` field — convert to array form with "null".
 82→    if let Some(ty) = obj.get("type").cloned() {
 83→        if let Some(s) = ty.as_str() {
 84→            obj.insert("type".to_string(), serde_json::json!([s, "null"]));
 85→        } else if let Some(arr) = ty.as_array() {
 86→            let mut new_arr = arr.clone();
 87→            new_arr.push(serde_json::json!("null"));
 88→            obj.insert("type".to_string(), serde_json::Value::Array(new_arr));
 89→        }
 90→        return;
 91→    }
 92→
 93→    // Case 2: uses anyOf/oneOf — append a null variant.
 94→    for key in ["anyOf", "oneOf"] {
 95→        if let Some(variants) = obj.get_mut(key).and_then(|v| v.as_array_mut()) {
 96→            let has_null = variants
 97→                .iter()
 98→                .any(|v| v.get("type").and_then(|t| t.as_str()) == Some("null"));
 99→            if !has_null {
100→                variants.push(serde_json::json!({"type": "null"}));
101→            }
102→            return;
103→        }
104→    }
105→}
106→
107→/// Recursively patch schema for OpenAI strict mode compliance.
108→///
109→/// OpenAI's strict mode requires:
110→/// 1. `additionalProperties: false` on every object in the schema tree
111→/// 2. All properties must be listed in the `required` array
112→///
113→/// Properties not in the original `required` array are made nullable so the
114→/// model can send `null` for unused optional fields instead of fabricating
115→/// placeholder values.
116→///
117→/// This function recursively patches nested objects in `properties`, array
118→/// `items`, `anyOf`/`oneOf`/`allOf` variants, etc.
119→pub fn patch_schema_for_strict_mode(schema: &mut serde_json::Value) {
120→    let Some(obj) = schema.as_object_mut() else {
121→        return;
122→    };
123→
124→    // Collect originally-optional property names so we can make them nullable
125→    // AFTER recursion (otherwise changing "type":"object" to ["object","null"]
126→    // would prevent the recursive pass from recognising nested objects).
127→    let mut optional_props: Vec<String> = Vec::new();
128→
129→    // If this is an object type, apply strict mode requirements
130→    if obj.get("type").and_then(|t| t.as_str()) == Some("object") {
131→        // Add additionalProperties: false
132→        obj.insert("additionalProperties".to_string(), serde_json::json!(false));
133→
134→        // Ensure all properties are in required array.
135→        if let Some(props) = obj.get("properties").and_then(|p| p.as_object()).cloned() {
136→            let originally_required: std::collections::HashSet<String> = obj
137→                .get("required")
138→                .and_then(|r| r.as_array())
139→                .map(|arr| {
140→                    arr.iter()
141→                        .filter_map(|v| v.as_str().map(String::from))
142→                        .collect()
143→                })
144→                .unwrap_or_default();
145→
146→            let all_prop_names: Vec<serde_json::Value> =
147→                props.keys().map(|k| serde_json::json!(k)).collect();
148→            obj.insert("required".to_string(), serde_json::json!(all_prop_names));
149→
150→            // Remember which properties need to be made nullable (deferred).
151→            for key in props.keys() {
152→                if !originally_required.contains(key) {
153→                    optional_props.push(key.clone());
154→                }
155→            }
156→        } else {
157→            // Object without properties - add empty properties and required
158→            obj.insert("properties".to_string(), serde_json::json!({}));
159→            obj.insert("required".to_string(), serde_json::json!([]));
160→        }
161→    }
162→
163→    // Recurse into properties
164→    if let Some(props) = obj.get_mut("properties").and_then(|p| p.as_object_mut()) {
165→        for (_, prop_schema) in props.iter_mut() {
166→            patch_schema_for_strict_mode(prop_schema);
167→        }
168→    }
169→
170→    // Recurse into array items
171→    if let Some(items) = obj.get_mut("items") {
172→        patch_schema_for_strict_mode(items);
173→    }
174→
175→    // Recurse into anyOf/oneOf/allOf
176→    for key in ["anyOf", "oneOf", "allOf"] {
177→        if let Some(variants) = obj.get_mut(key).and_then(|v| v.as_array_mut()) {
178→            for variant in variants {
179→                patch_schema_for_strict_mode(variant);
180→            }
181→        }
182→    }
183→
184→    // Recurse into additionalProperties if it's a schema (not just true/false)
185→    if let Some(additional) = obj.get_mut("additionalProperties")
186→        && additional.is_object()
187→    {
188→        patch_schema_for_strict_mode(additional);
189→    }
190→
191→    // Now that recursion is done, make originally-optional properties nullable
192→    // so the model can send `null` instead of fabricating placeholder values
193→    // (e.g. empty strings) that downstream MCP servers reject.
194→    if !optional_props.is_empty()
195→        && let Some(props) = obj.get_mut("properties").and_then(|p| p.as_object_mut())
196→    {
197→        for key in &optional_props {
198→            if let Some(prop_schema) = props.get_mut(key) {
199→                make_nullable(prop_schema);
200→            }
201→        }
202→    }
203→}
204→
205→/// Convert tool schemas to OpenAI Chat Completions function-calling format.
206→///
207→/// Uses the nested `function` object format required by Chat Completions API:
208→/// ```json
209→/// { "type": "function", "function": { "name": "...", ... } }
210→/// ```
211→///
212→/// Adds `strict: true` and patches schemas for strict mode compliance:
213→/// - `additionalProperties: false` on all object schemas
214→/// - All properties included in `required` array
215→///
216→/// This is required by some APIs (Claude via Copilot) to ensure the model
217→/// provides all required fields.
218→///
219→/// See: <https://platform.openai.com/docs/guides/function-calling>
220→pub fn to_openai_tools(tools: &[serde_json::Value]) -> Vec<serde_json::Value> {
221→    let result: Vec<serde_json::Value> = tools
222→        .iter()
223→        .filter_map(|t| {
224→            // Clone parameters and patch for strict mode
225→            let mut params = t["parameters"].clone();
226→            patch_schema_for_strict_mode(&mut params);
227→
228→            let name = t["name"].as_str()?.to_string();
229→            let description = t["description"].as_str().unwrap_or("").to_string();
230→
231→            // Use typed struct to ensure all required fields are present
232→            let tool = ChatCompletionsTool {
233→                tool_type: "function",
234→                function: ChatCompletionsFunction {
235→                    name: name.clone(),
236→                    description,
237→                    parameters: params,
238→                    strict: true,
239→                },
240→            };
241→
242→            trace!(tool_name = %name, "converted tool to Chat Completions format");
243→
244→            // Serialize to Value for compatibility with existing API
245→            serde_json::to_value(tool).ok()
246→        })
247→        .collect();
248→
249→    trace!(tools_count = result.len(), "to_openai_tools complete");
250→    result
251→}
252→
253→/// Convert tool schemas to OpenAI Responses API function-calling format.
254→///
255→/// Uses the flat format required by the Responses API where `name` is at top level:
256→/// ```json
257→/// { "type": "function", "name": "...", "parameters": {...}, "strict": true }
258→/// ```
259→///
260→/// This is the format used by OpenAI Codex and the Responses API.
261→///
262→/// Patches schemas for strict mode compliance:
263→/// - `additionalProperties: false` on all object schemas
264→/// - All properties included in `required` array
265→///
266→/// See: <https://learn.microsoft.com/en-us/azure/ai-foundry/openai/how-to/responses>
267→pub fn to_responses_api_tools(tools: &[serde_json::Value]) -> Vec<serde_json::Value> {
268→    let result: Vec<serde_json::Value> = tools
269→        .iter()
270→        .filter_map(|t| {
271→            // Clone parameters and patch for strict mode
272→            let mut params = t["parameters"].clone();
273→            patch_schema_for_strict_mode(&mut params);
274→
275→            let name = t["name"].as_str()?.to_string();
276→            let description = t["description"].as_str().unwrap_or("").to_string();
277→
278→            // Use typed struct to ensure all required fields are present
279→            let tool = ResponsesApiTool {
280→                tool_type: "function",
281→                name: name.clone(),
282→                description,
283→                parameters: params,
284→                strict: true,
285→            };
286→
287→            trace!(tool_name = %name, "converted tool to Responses API format");
288→
289→            // Serialize to Value for compatibility with existing API
290→            serde_json::to_value(tool).ok()
291→        })
292→        .collect();
293→
294→    trace!(
295→        tools_count = result.len(),
296→        "to_responses_api_tools complete"
297→    );
298→    result
299→}
300→
301→/// Convert typed chat messages to Responses API input items.
302→///
303→/// Responses API accepts a heterogeneous input array (messages, tool calls, and
304→/// tool outputs). This keeps one canonical conversion for providers that use
305→/// Responses transport (SSE or WebSocket).
306→#[must_use]
307→pub fn to_responses_input(messages: &[ChatMessage]) -> Vec<serde_json::Value> {
308→    messages
309→        .iter()
310→        .flat_map(|msg| match msg {
311→            ChatMessage::System { .. } => {
312→                // System messages are extracted into `instructions`.
313→                vec![]
314→            },
315→            ChatMessage::User { content } => {
316→                let content_blocks = match content {
317→                    UserContent::Text(t) => {
318→                        vec![serde_json::json!({"type": "input_text", "text": t})]
319→                    },
320→                    UserContent::Multimodal(parts) => parts
321→                        .iter()
322→                        .map(|p| match p {
323→                            moltis_agents::model::ContentPart::Text(t) => {
324→                                serde_json::json!({"type": "input_text", "text": t})
325→                            },
326→                            moltis_agents::model::ContentPart::Image { media_type, data } => {
327→                                let data_uri = format!("data:{media_type};base64,{data}");
328→                                serde_json::json!({
329→                                    "type": "input_image",
330→                                    "image_url": data_uri,
331→                                })
332→                            },
333→                        })
334→                        .collect(),
335→                };
336→                vec![serde_json::json!({
337→                    "role": "user",
338→                    "content": content_blocks,
339→                })]
340→            },
341→            ChatMessage::Assistant {
342→                content,
343→                tool_calls,
344→            } => {
345→                if !tool_calls.is_empty() {
346→                    let mut items: Vec<serde_json::Value> = tool_calls
347→                        .iter()
348→                        .map(|tc| {
349→                            serde_json::json!({
350→                                "type": "function_call",
351→                                "call_id": tc.id,
352→                                "name": tc.name,
353→                                "arguments": tc.arguments.to_string(),
354→                            })
355→                        })
356→                        .collect();
357→                    if let Some(text) = content
358→                        && !text.is_empty()
359→                    {
360→                        items.insert(
361→                            0,
362→                            serde_json::json!({
363→                                "type": "message",
364→                                "role": "assistant",
365→                                "content": [{"type": "output_text", "text": text}]
366→                            }),
367→                        );
368→                    }
369→                    items
370→                } else {
371→                    let text = content.as_deref().unwrap_or("");
372→                    vec![serde_json::json!({
373→                        "type": "message",
374→                        "role": "assistant",
375→                        "content": [{"type": "output_text", "text": text}]
376→                    })]
377→                }
378→            },
379→            ChatMessage::Tool {
380→                tool_call_id,
381→                content,
382→            } => {
383→                vec![serde_json::json!({
384→                    "type": "function_call_output",
385→                    "call_id": tool_call_id,
386→                    "output": content,
387→                })]
388→            },
389→        })
390→        .collect()
391→}
