393→/// Parse tool_calls from an OpenAI response message (non-streaming).
394→pub fn parse_tool_calls(message: &serde_json::Value) -> Vec<ToolCall> {
395→    message["tool_calls"]
396→        .as_array()
397→        .map(|tcs| {
398→            tcs.iter()
399→                .filter_map(|tc| {
400→                    let id = tc["id"].as_str()?.to_string();
401→                    let name = tc["function"]["name"].as_str()?.to_string();
402→                    let args_str = tc["function"]["arguments"].as_str().unwrap_or("{}");
403→                    let arguments = serde_json::from_str(args_str).unwrap_or(serde_json::json!({}));
404→                    Some(ToolCall {
405→                        id,
406→                        name,
407→                        arguments,
408→                    })
409→                })
410→                .collect()
411→        })
412→        .unwrap_or_default()
413→}
