415→fn usage_value_at_path(usage: &serde_json::Value, path: &[&str]) -> Option<u64> {
416→    let mut cursor = usage;
417→    for key in path {
418→        cursor = cursor.get(*key)?;
419→    }
420→    cursor
421→        .as_u64()
422→        .or_else(|| cursor.as_str().and_then(|raw| raw.parse::<u64>().ok()))
423→}
424→
425→fn usage_field_u32(usage: &serde_json::Value, paths: &[&[&str]]) -> u32 {
426→    paths
427→        .iter()
428→        .find_map(|path| usage_value_at_path(usage, path))
429→        .unwrap_or(0) as u32
430→}
