436→
437→    if let Some(usage) = payload
438→        .get("choices")
439→        .and_then(serde_json::Value::as_array)
440→        .and_then(|choices| choices.first())
441→        .and_then(|choice| choice.get("usage"))
442→        .filter(|usage| usage.is_object())
443→    {
444→        return Some(usage);
445→    }
446→
447→    if let Some(usage) = payload
448→        .get("choices")
449→        .and_then(serde_json::Value::as_array)
450→        .and_then(|choices| choices.first())
451→        .and_then(|choice| choice.get("delta"))
452→        .and_then(|delta| delta.get("usage"))
453→        .filter(|usage| usage.is_object())
454→    {
455→        return Some(usage);
456→    }
457→
458→    if let Some(usage) = payload
459→        .get("choices")
460→        .and_then(serde_json::Value::as_array)
461→        .and_then(|choices| choices.first())
462→        .and_then(|choice| choice.get("message"))
463→        .and_then(|message| message.get("usage"))
464→        .filter(|usage| usage.is_object())
