526→/// Strip `<think>...</think>` tags from content, returning `(visible, thinking)`.
527→///
528→/// Models like DeepSeek R1, QwQ, and MiniMax embed chain-of-thought reasoning
529→/// inside `<think>` tags in the `content` field rather than using a separate
530→/// `reasoning_content` field.  This helper splits content into the visible
531→/// answer text and the thinking text so callers can handle them appropriately.
532→///
533→/// Edge cases handled:
534→/// - Multiple `<think>` blocks interspersed with answer text
535→/// - Unclosed `<think>` tag (remainder treated as reasoning)
536→/// - Empty `<think></think>` blocks
537→/// - Nested angle brackets inside thinking text
538→pub fn strip_think_tags(content: &str) -> (String, String) {
539→    let mut visible = String::new();
540→    let mut thinking = String::new();
541→    let mut remaining = content;
542→
543→    loop {
544→        match remaining.find("<think>") {
545→            Some(start) => {
546→                // Text before <think> is visible
547→                visible.push_str(&remaining[..start]);
548→                let after_open = &remaining[start + "<think>".len()..];
549→                match after_open.find("</think>") {
550→                    Some(end) => {
551→                        thinking.push_str(&after_open[..end]);
552→                        remaining = &after_open[end + "</think>".len()..];
553→                    },
554→                    None => {
555→                        // Unclosed <think> — treat rest as reasoning
556→                        thinking.push_str(after_open);
557→                        break;
558→                    },
559→                }
560→            },
561→            None => {
562→                visible.push_str(remaining);
563→                break;
564→            },
565→        }
566→    }
567→
568→    (
569→        visible.trim_start().to_string(),
570→        thinking.trim_start().to_string(),
571→    )
572→}
