608→/// Emit a `ReasoningDelta`, stripping leading whitespace at the start of a
609→/// think block so the UI doesn't show a blank prefix.
610→fn emit_reasoning(text: String, strip_leading_ws: &mut bool, events: &mut Vec<StreamEvent>) {
611→    if text.is_empty() {
612→        return;
613→    }
614→    let emitted = if *strip_leading_ws {
615→        let trimmed = text.trim_start();
616→        if trimmed.is_empty() {
617→            // Entire chunk was whitespace — keep stripping
618→            return;
619→        }
620→        *strip_leading_ws = false;
621→        trimmed.to_string()
622→    } else {
623→        text
624→    };
625→    events.push(StreamEvent::ReasoningDelta(emitted));
626→}
627→
628→/// Emit a visible `Delta`, stripping leading whitespace after a `</think>`
629→/// block so the UI doesn't show blank lines before the answer.
630→fn emit_visible(text: String, strip_leading_ws: &mut bool, events: &mut Vec<StreamEvent>) {
631→    if text.is_empty() {
632→        return;
633→    }
634→    let emitted = if *strip_leading_ws {
635→        let trimmed = text.trim_start();
636→        if trimmed.is_empty() {
637→            // Entire chunk was whitespace — keep stripping
638→            return;
639→        }
640→        *strip_leading_ws = false;
641→        trimmed.to_string()
642→    } else {
643→        text
644→    };
645→    events.push(StreamEvent::Delta(emitted));
646→}
