648→/// Process streamed content through the `<think>` tag state machine.
649→///
650→/// Content arriving inside `<think>...</think>` is emitted as
651→/// `ReasoningDelta`; content outside is emitted as `Delta`.
652→/// Tags may be split across SSE chunks — `tag_buffer` accumulates
653→/// partial tag fragments until they can be resolved.
654→/// Leading whitespace at the start of each think block is stripped.
655→fn process_content_think_tags(
656→    content: &str,
657→    state: &mut StreamingToolState,
658→    events: &mut Vec<StreamEvent>,
659→) {
660→    state.tag_buffer.push_str(content);
661→
662→    loop {
663→        if state.in_think_block {
664→            // Look for </think> to exit think mode
665→            match state.tag_buffer.find("</think>") {
666→                Some(pos) => {
667→                    let thinking = state.tag_buffer[..pos].to_string();
668→                    emit_reasoning(thinking, &mut state.think_strip_leading_ws, events);
669→                    state.in_think_block = false;
670→                    state.visible_strip_leading_ws = true;
671→                    let rest = state.tag_buffer[pos + "</think>".len()..].to_string();
672→                    state.tag_buffer = rest;
673→                    // Continue loop to process remaining content
674→                },
675→                None => {
676→                    // Check if buffer ends with a prefix of "</think>"
677→                    // to avoid emitting partial tag as reasoning text.
678→                    let suffix_match = longest_tag_suffix(&state.tag_buffer, "</think>");
679→                    if suffix_match > 0 {
680→                        let safe = state.tag_buffer.len() - suffix_match;
681→                        let emit = state.tag_buffer[..safe].to_string();
682→                        emit_reasoning(emit, &mut state.think_strip_leading_ws, events);
683→                        let kept = state.tag_buffer[safe..].to_string();
684→                        state.tag_buffer = kept;
685→                    } else {
686→                        // No partial tag — emit everything as reasoning
687→                        let buf = std::mem::take(&mut state.tag_buffer);
688→                        emit_reasoning(buf, &mut state.think_strip_leading_ws, events);
689→                    }
690→                    break;
691→                },
692→            }
693→        } else {
694→            // Look for <think> to enter think mode
695→            match state.tag_buffer.find("<think>") {
696→                Some(pos) => {
697→                    let visible = state.tag_buffer[..pos].to_string();
698→                    emit_visible(visible, &mut state.visible_strip_leading_ws, events);
699→                    state.in_think_block = true;
700→                    state.think_strip_leading_ws = true;
701→                    let rest = state.tag_buffer[pos + "<think>".len()..].to_string();
702→                    state.tag_buffer = rest;
703→                    // Continue loop to process remaining content
704→                },
705→                None => {
706→                    // Check if buffer ends with a prefix of "<think>"
707→                    let suffix_match = longest_tag_suffix(&state.tag_buffer, "<think>");
708→                    if suffix_match > 0 {
709→                        let safe = state.tag_buffer.len() - suffix_match;
710→                        let emit = state.tag_buffer[..safe].to_string();
711→                        emit_visible(emit, &mut state.visible_strip_leading_ws, events);
712→                        let kept = state.tag_buffer[safe..].to_string();
713→                        state.tag_buffer = kept;
714→                    } else {
715→                        // No partial tag — emit everything as visible
716→                        let buf = std::mem::take(&mut state.tag_buffer);
717→                        emit_visible(buf, &mut state.visible_strip_leading_ws, events);
718→                    }
719→                    break;
720→                },
721→            }
722→        }
723→    }
