757→    }
758→
759→    let Ok(evt) = serde_json::from_str::<serde_json::Value>(data) else {
760→        return SseLineResult::Skip;
761→    };
762→
763→    let mut events = vec![StreamEvent::ProviderRaw(evt.clone())];
764→
765→    if let Some(usage) = parse_openai_compat_usage_from_payload(&evt) {
