780→
781→    // Some OpenAI-compatible backends stream planning text in
782→    // `reasoning_content` or `reasoning`. Surface it separately so UI can
783→    //  show it in the thinking area without polluting final assistant text.
784→    let reasoning_text = delta["reasoning_content"]
