791→    }
792→
793→    // Handle tool calls
794→    if let Some(tcs) = delta["tool_calls"].as_array() {
795→        for tc in tcs {
796→            let index = tc["index"].as_u64().unwrap_or(0) as usize;
797→
798→            // Check if this is a new tool call (has id and function.name)
799→            if let (Some(id), Some(name)) = (tc["id"].as_str(), tc["function"]["name"].as_str()) {
800→                state
