    #[test]
    fn test_to_openai_tools_nested_objects() {
        // Test that nested objects get additionalProperties: false
        let tools = vec![serde_json::json!({
            "name": "nested_tool",
            "description": "Tool with nested objects",
            "parameters": {
                "type": "object",
                "properties": {
                    "outer": {
                        "type": "object",
                        "properties": {
                            "inner": {
                                "type": "object",
                                "properties": {
                                    "value": {"type": "string"}
                                }
                            }
                        }
                    }
                }
            }
