    fn test_to_openai_tools_anyof() {
        // Test that anyOf/oneOf/allOf variants get additionalProperties: false
        let tools = vec![serde_json::json!({
            "name": "union_tool",
            "description": "Tool with anyOf",
            "parameters": {
