    #[test]
    fn with_reasoning_effort_creates_new_provider() {
        use moltis_agents::model::{LlmProvider, ReasoningEffort};
        let provider = Arc::new(OpenAiProvider::new(
            Secret::new("test-key".into()),
            "o3".into(),
