 844→                        let retry_after_ms = super::retry_after_ms_from_headers(r.headers());
 845→                        let body_text = r.text().await.unwrap_or_default();
 846→
 847→                        // Fallback: if this is an unsupported API error,
 848→                        // switch to Responses API streaming.
 849→                        if status == 400
 850→                            && is_responses_api_required_error(&body_text)
 851→                        {
 852→                            debug!(
 853→                                model = %self.model,
 854→                                "chat completions returned unsupported_api_for_model, \
 855→                                 falling back to responses API streaming"
 856→                            );
 857→                            let mut responses_stream =
 858→                                self.stream_responses_api(messages, tools);
 859→                            while let Some(event) = responses_stream.next().await {
 860→                                yield event;
 861→                            }
 862→                            return;
 863→                        }
 864→
 865→                        yield StreamEvent::Error(super::with_retry_after_marker(
 866→                            format!("HTTP {status}: {body_text}"),
 867→                            retry_after_ms,
 868→                        ));
 869→                        return;
 870→                    }
 871→                    r
 872→                }
 873→                Err(e) => {
 874→                    yield StreamEvent::Error(e.to_string());
 875→                    return;
 876→                }
 877→            };
 878→
 879→            let mut byte_stream = resp.bytes_stream();
 880→            let mut buf = String::new();
 881→            let mut state = StreamingToolState::default();
 882→
 883→            while let Some(chunk) = byte_stream.next().await {
 884→                let chunk = match chunk {
 885→                    Ok(c) => c,
 886→                    Err(e) => {
 887→                        yield StreamEvent::Error(e.to_string());
 888→                        return;
 889→                    }
 890→                };
 891→                buf.push_str(&String::from_utf8_lossy(&chunk));
 892→
 893→                while let Some(pos) = buf.find('\n') {
 894→                    let line = buf[..pos].trim().to_string();
 895→                    buf = buf[pos + 1..].to_string();
 896→
 897→                    if line.is_empty() {
 898→                        continue;
 899→                    }
 900→
 901→                    let Some(data) = line
 902→                        .strip_prefix("data: ")
 903→                        .or_else(|| line.strip_prefix("data:"))
 904→                    else {
 905→                        continue;
 906→                    };
 907→
 908→                    match process_openai_sse_line(data, &mut state) {
 909→                        SseLineResult::Done => {
 910→                            for event in finalize_stream(&mut state) {
 911→                                yield event;
 912→                            }
 913→                            return;
 914→                        }
 915→                        SseLineResult::Events(events) => {
 916→                            for event in events {
 917→                                yield event;
 918→                            }
 919→                        }
 920→                        SseLineResult::Skip => {}
 921→                    }
 922→                }
 923→            }
 924→
 925→            let line = buf.trim().to_string();
 926→            if !line.is_empty()
 927→                && let Some(data) = line
 928→                    .strip_prefix("data: ")
 929→                    .or_else(|| line.strip_prefix("data:"))
 930→            {
 931→                match process_openai_sse_line(data, &mut state) {
 932→                    SseLineResult::Done => {
 933→                        for event in finalize_stream(&mut state) {
 934→                            yield event;
 935→                        }
 936→                        return;
 937→                    }
 938→                    SseLineResult::Events(events) => {
 939→                        for event in events {
 940→                            yield event;
 941→                        }
 942→                    }
 943→                    SseLineResult::Skip => {}
 944→                }
 945→            }
 946→
 947→            for event in finalize_stream(&mut state) {
 948→                yield event;
 949→            }
 950→        })
 951→    }
 952→}
